def remove_oldest(self, *, remove_pinned: bool = False) -> None:
    if len(self) == 0:
        return

    self.popitem(remove_pinned=remove_pinned)

def _remove_old_if_needed(self) -> None:
    while self.currsize > self.capacity:
        self.remove_oldest()

